#include "pressure_fsr.h"
#include <Arduino.h>
#define FSR_PIN 34
static int _raw=0;static float _force=0;static bool _pressed=false;static unsigned long _l=0;
void fsr_setup(){pinMode(FSR_PIN,INPUT);Serial.println("[fsr] OK");}
void fsr_loop(){if(millis()-_l<100)return;_l=millis();_raw=analogRead(FSR_PIN);_force=_raw*10.0/4095.0;_pressed=_raw>200;}
int fsr_get_raw(){return _raw;}
float fsr_get_force_n(){return _force;}
bool fsr_pressed(){return _pressed;}
